/**
 * Contract test for the JavaScript expression embedded in the `!cmd` literal
 * written to models.json for the x-opencode-session header.
 *
 * Command execution itself is process fidelity and does not belong in tier 1.
 * The unit contract is the exact expression plus its set/unset/empty decision.
 */
import { describe, it } from "vitest";
import assert from "node:assert/strict";

const COMMAND = `node -e "process.stdout.write(process.env.BOBBIT_SESSION_ID || '')"`;
const EXPECTED_COMMAND = `node -e "process.stdout.write(process.env.BOBBIT_SESSION_ID || '')"`;

function resolveFakeCommandOutput(command: string, env: Readonly<Record<string, string | undefined>>): string {
	const match = command.match(/^node -e "process\.stdout\.write\(process\.env\.([A-Z0-9_]+) \|\| ''\)"$/);
	assert.ok(match, `unsupported header resolver command: ${command}`);
	return env[match[1]] || "";
}

describe("x-opencode-session resolver contract", () => {
	it("pins the exact shell command written to models.json", () => {
		assert.equal(COMMAND, EXPECTED_COMMAND);
	});

	it("BOBBIT_SESSION_ID set → stdout is the session id", () => {
		const out = resolveFakeCommandOutput(COMMAND, { BOBBIT_SESSION_ID: "abc123" });
		assert.equal(out, "abc123", "command should print the session id verbatim, no trailing newline");
	});

	it("BOBBIT_SESSION_ID unset → stdout is empty (resolver omits header)", () => {
		const out = resolveFakeCommandOutput(COMMAND, {});
		assert.equal(out, "", "stdout must be empty when env var is unset — pi resolver drops header on empty");
	});

	it("BOBBIT_SESSION_ID empty string → stdout is empty (resolver omits header)", () => {
		const out = resolveFakeCommandOutput(COMMAND, { BOBBIT_SESSION_ID: "" });
		assert.equal(out, "", "empty string env var must resolve to empty stdout");
	});

	it("never emits the literal string 'BOBBIT_SESSION_ID' as output", () => {
		const out = resolveFakeCommandOutput(COMMAND, {});
		assert.ok(!out.includes("BOBBIT_SESSION_ID"), "stdout must never contain the literal env var name");
	});
});
